using AzureMcp.Areas.Storage.Options.DataLake.Directory;
using AzureMcp.Areas.Storage.Services;
using AzureMcp.Commands.Storage;
using AzureMcp.Services.Telemetry;
using Microsoft.Extensions.Logging;

namespace AzureMcp.Areas.Storage.Commands.DataLake.Directory;

public sealed class DirectoryCreateCommand(ILogger<DirectoryCreateCommand> logger) : BaseDirectoryCommand<DirectoryCreateOptions>
{
    private const string CommandTitle = "Create Data Lake Directory";
    private readonly ILogger<DirectoryCreateCommand> _logger = logger;

    public override string Name => "create";

    public override string Description =>
        """
        Create a directory in a Data Lake file system. This command creates a new directory at the specified path
        within a Data Lake Storage Gen2 file system. The directory path can include multiple levels (e.g., 'folder1/folder2').
        If parent directories don't exist, they will be created automatically. Returns the created directory path.
        Required options: account-name, file-system-name, directory-path.
        """;

    public override string Title => CommandTitle;

    [McpServerTool(Destructive = false, ReadOnly = false, Title = CommandTitle)]
    public override async Task<CommandResponse> ExecuteAsync(CommandContext context, ParseResult parseResult)
    {
        var options = BindOptions(parseResult);

        try
        {
            if (!Validate(parseResult.CommandResult, context.Response).IsValid)
            {
                return context.Response;
            }

            context.Activity?.WithSubscriptionTag(options);

            var storageService = context.GetService<IStorageService>();
            var directoryPath = await storageService.CreateDataLakeDirectory(
                options.Account!,
                options.FileSystem!,
                options.DirectoryPath!,
                options.Subscription!,
                options.Tenant,
                options.RetryPolicy);

            context.Response.Results = ResponseResult.Create(
                new DirectoryCreateCommandResult(directoryPath),
                StorageJsonContext.Default.DirectoryCreateCommandResult);
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error creating Data Lake directory. Account: {Account}, FileSystem: {FileSystem}, DirectoryPath: {DirectoryPath}.",
                options.Account, options.FileSystem, options.DirectoryPath);
            HandleException(context, ex);
        }

        return context.Response;
    }

    internal record DirectoryCreateCommandResult(string DirectoryPath);
}

